//========================================================================================================================================================================================================200
//	WRAPPER FUNCTION
//========================================================================================================================================================================================================200

#ifdef __cplusplus
extern "C" {
#endif

void kernel_gpu_cuda_wrapper(
    par_str parms_cpu,
    dim_str dim_cpu,
    box_str* box_cpu,
    FOUR_VECTOR* rv_cpu,
    fp* qv_cpu,
    FOUR_VECTOR* fv_cpu)
{
    long long time0, time1, time2, time3, time4, time5, time6;

    time0 = get_time();

    setdevice();

    time1 = get_time();

    box_str* box_gpu;
    FOUR_VECTOR* rv_gpu;
    fp* qv_gpu;
    FOUR_VECTOR* fv_gpu;

    cudaMalloc((void**)&box_gpu, dim_cpu.box_mem);
    checkCUDAError("cudaMalloc box_gpu");

    cudaMalloc((void**)&rv_gpu, dim_cpu.space_mem);
    checkCUDAError("cudaMalloc rv_gpu");

    cudaMalloc((void**)&qv_gpu, dim_cpu.space_mem2);
    checkCUDAError("cudaMalloc qv_gpu");

    cudaMalloc((void**)&fv_gpu, dim_cpu.space_mem);
    checkCUDAError("cudaMalloc fv_gpu");

    time2 = get_time();

    cudaMemcpy(box_gpu, box_cpu, dim_cpu.box_mem, cudaMemcpyHostToDevice);
    checkCUDAError("cudaMemcpy box_gpu");

    cudaMemcpy(rv_gpu, rv_cpu, dim_cpu.space_mem, cudaMemcpyHostToDevice);
    checkCUDAError("cudaMemcpy rv_gpu");

    cudaMemcpy(qv_gpu, qv_cpu, dim_cpu.space_mem2, cudaMemcpyHostToDevice);
    checkCUDAError("cudaMemcpy qv_gpu");

    cudaMemcpy(fv_gpu, fv_cpu, dim_cpu.space_mem, cudaMemcpyHostToDevice);
    checkCUDAError("cudaMemcpy fv_gpu");

    time3 = get_time();

    dim3 gridDim(dim_cpu.number_boxes, 1, 1);
    dim3 blockDim(NUMBER_PAR_PER_BOX, 1, 1);

    kernel_gpu_cuda<<<gridDim, blockDim>>>(
        parms_cpu,
        dim_cpu,
        box_gpu,
        rv_gpu,
        qv_gpu,
        fv_gpu);

    cudaDeviceSynchronize();
    checkCUDAError("kernel_gpu_cuda");

    time4 = get_time();

    cudaMemcpy(fv_cpu, fv_gpu, dim_cpu.space_mem, cudaMemcpyDeviceToHost);
    checkCUDAError("cudaMemcpy fv_cpu");

    time5 = get_time();

    cudaFree(box_gpu);
    cudaFree(rv_gpu);
    cudaFree(qv_gpu);
    cudaFree(fv_gpu);

    time6 = get_time();

    printf("Time spent in different stages of GPU_CUDA KERNEL:\n");
    printf("%15.12f s, %15.12f %% : GPU: SET DEVICE\n",
        (float)(time1-time0)/1000000, (float)(time1-time0)/(float)(time6-time0)*100);
    printf("%15.12f s, %15.12f %% : GPU: MEM ALLOC\n",
        (float)(time2-time1)/1000000, (float)(time2-time1)/(float)(time6-time0)*100);
    printf("%15.12f s, %15.12f %% : GPU: HToD\n",
        (float)(time3-time2)/1000000, (float)(time3-time2)/(float)(time6-time0)*100);
    printf("%15.12f s, %15.12f %% : GPU: KERNEL\n",
        (float)(time4-time3)/1000000, (float)(time4-time3)/(float)(time6-time0)*100);
    printf("%15.12f s, %15.12f %% : GPU: DToH\n",
        (float)(time5-time4)/1000000, (float)(time5-time4)/(float)(time6-time0)*100);
    printf("%15.12f s, %15.12f %% : GPU: MEM FREE\n",
        (float)(time6-time5)/1000000, (float)(time6-time5)/(float)(time6-time0)*100);
    printf("Total time:\n");
    printf("%.12f s\n", (float)(time6-time0)/1000000);
}

#ifdef __cplusplus
}
#endif
